// 鏍囬鍦烘櫙
import { resetTimeManager } from '../systems/TimeManager';
import SaveLoadManager from '../systems/SaveLoadManager';
import AchievementManager from '../systems/AchievementManager';
import { getBgmManager } from '../systems/BgmManager';

class TitleScene extends Phaser.Scene {
  constructor() {
    super({ key: 'TitleScene' });
  }

  create() {
    const centerX = this.cameras.main.width / 2;
    const centerY = this.cameras.main.height / 2;

    // 鎾斁涓昏彍鍗?BGM锛堟祻瑙堝櫒鑷姩鎾斁闄愬埗涓嬪彲鑳借鎷︽埅锛?
    getBgmManager().play('mainMenu');

    // 棣栨鐐瑰嚮娓告垙鐢婚潰鏃惰В閿佸苟閲嶈瘯 BGM 鎾斁
    this.input.once('pointerdown', () => {
      getBgmManager().markUserInteracted();
      getBgmManager().play('mainMenu');
    });

    // 鏍囬鑳屾櫙
    this.add.rectangle(centerX, centerY, 800, 600, 0x1a1a2e);
    
    // 瑁呴グ绾?
    this.add.rectangle(centerX, 150, 500, 2, 0x4a4a6a);
    this.add.rectangle(centerX, 450, 500, 2, 0x4a4a6a);

    // 娓告垙鏍囬
    this.titleText = this.add.text(centerX, 100, '涓囦簨灞嬬偧閲戠墿璇?, {
      fontSize: '48px',
      fontFamily: 'Georgia, serif',
      color: '#88c0d0',
      fontStyle: 'bold'
    }).setOrigin(0.5);

    // 鍓爣棰?
    this.add.text(centerX, 200, "~ Mendel's General Store ~", {
      fontSize: '16px',
      fontFamily: 'Georgia, serif',
      color: '#d08770',
      fontStyle: 'italic'
    }).setOrigin(0.5);

    // 鐐奸噾閿呭浘鏍囷紙鐢ㄦ枃瀛楁ā鎷燂級
    this.alchemyIcon = this.add.text(centerX, 300, '鈿楋笍', {
      fontSize: '64px'
    }).setOrigin(0.5);

    // 鍔ㄧ敾鏁堟灉
    this.tweens.add({
      targets: this.alchemyIcon,
      scale: { from: 1, to: 1.1 },
      duration: 1000,
      yoyo: true,
      repeat: -1,
      ease: 'Sine.easeInOut'
