try {
  const { chromium } = await import('playwright');
  var browser = await chromium.launch({ headless: true });
  var page = await browser.newPage({ viewport: { width: 1366, height: 768 }, deviceScaleFactor: 1 });
  await page.goto('http://127.0.0.1:5174/', { waitUntil: 'networkidle' });
  await page.waitForTimeout(1500);
  const titleVisible = await page.getByText('万事屋炼金物语').isVisible().catch(() => false);
  const startVisible = await page.getByText('开始游戏').isVisible().catch(() => false);
  const continueVisible = await page.getByText('继续游戏').isVisible().catch(() => false);
  const screenshot = await page.screenshot({ fullPage: false });
  await browser.close();
  await nodeRepl.emitImage({ bytes: screenshot, mimeType: 'image/png' });
  nodeRepl.write(JSON.stringify({ titleVisible, startVisible, continueVisible }, null, 2));
} catch (error) {
  nodeRepl.write(JSON.stringify({ error: String(error && error.message ? error.message : error) }, null, 2));
}

