  const fsp = await import('node:fs/promises');
  const pathMod = await import('node:path');
  const rootDir = nodeRepl.cwd;
  const itemsJson = JSON.parse(await fsp.readFile(pathMod.join(rootDir, 'src/data/items.json'), 'utf8')).items;
  const urls = [
    '/assets/scene-pieces/tiles_atlas32.png',
    ...['Book','Carpet','Cauldron','Clock','Decorate1','Decorate2','Desk','Door','Fridge','Painting','Quest','Sofa1','Sofa2','Lantern1','Lantern2','Window'].map(n=>`/assets/scene-pieces/furniture${n}.png`),
    '/assets/scene-pieces/floor_wood_clean.png',
    '/assets/scene-pieces/wall_warm_clean.png',
    '/assets/scene-pieces/fireplace_fancy_full2.png',
    '/assets/scene-pieces/bed_fancy_brown.png',
    '/assets/super-retro-world/interior/animation/fire.png',
    '/assets/super-retro-world/interior/animation/fire2.png',
    ...['book','clock','decorate1','decorate2','desk','door','fridge','painting','quest','sofa1','sofa2','lantern1','lantern2','window'].map(n=>`/assets/craft_furniture_transparent/source_1x/${n}.png`),
    '/assets/processed/furniture/carpet.png',
    '/assets/processed/furniture/cauldron_pot-stpat.png',
    ...itemsJson.filter(i=>i.previewIcon && i.previewImage).map(i=>i.previewImage)
  ];
  const unique = [...new Set(urls)];
  const failures = [];
  for (const url of unique) {
    try {
      const res = await fetch('http://127.0.0.1:5174' + url, { method: 'HEAD' });
      if (!res.ok) failures.push({ url, status: res.status });
    } catch (e) {
      failures.push({ url, error: String(e.message || e) });
    }
  }
  nodeRepl.write(JSON.stringify({ checked: unique.length, failures }, null, 2));
